  ('locality-d592fc58-moex-00081', 'locality-d592fc58', 'locality-d592fc58-moex-112-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '下列關於代理人與代表之敘述，何者錯誤？', '["代理人與本人，係屬二個權利主體間之關係；代表與法人，係屬一個權利主體間之關係", "代理人以本人名義所為意思表示，其效果歸屬於本人；代表是法人機關，代表人所為行為，即 法人行為，並無效力之歸屬問題", "代理人與代表均得為法律行為與事實行為", "代理相關規定，得類推適用於代表"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:25+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "320", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
