  ('locality-d592fc58-moex-00083', 'locality-d592fc58', 'locality-d592fc58-moex-112-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '甲係一明星，擔心狗仔跟拍，入住旅館時，冒用友人名字李四登記住房。下列敘述何者正確？', '["甲未經李四授權，與旅館簽約係屬無權代理", "旅館對於入住房客發生當事人同一性錯誤", "旅館對於入住房客為甲並無誤認，亦有與甲訂約之意", "甲與旅館之間為通謀虛偽意思表示"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:25+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "320", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00084', 'locality-d592fc58', 'locality-d592fc58-moex-112-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '甲將其對乙之債權讓與於丙時，應具備下列何者要件，始得對乙發生效力？', '["甲、乙、丙三人之書面合意", "甲、乙、丙三人之口頭合意", "甲、丙達成合意，並應由甲與丙共同通知乙", "甲、丙達成合意，並應由甲或丙通知乙"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:25+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "320", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00085', 'locality-d592fc58', 'locality-d592fc58-moex-112-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '下列關於代理權消滅之敘述，何者正確？', '["代理人不得拋棄其代理權", "代理人死亡，代理權得為繼承之標的", "代理人喪失行為能力時，代理權消滅", "受僱人被解僱時，其代理權仍不消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:25+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "320", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00086', 'locality-d592fc58', 'locality-d592fc58-moex-112-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '當事人間無特別約定時，下列何種情形得互相主張同時履行抗辯權？', '["委任人償還費用之義務與受任人處理委任事務之義務", "清償人之給付與受領清償人之受領證書之給與", "承攬人交付完成物之義務與定作人給付報酬之義務", "承攬人返還定作物剩餘材料之義務與定作人給付報酬之義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:25+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "320", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00087', 'locality-d592fc58', 'locality-d592fc58-moex-112-9b7ab1bb', 'sub-locality-d592fc58-05', NULL, 'single_choice', '甲建設公司與乙營造廠訂立承攬契約，委託乙興建大樓；乙之受僱人丙於搭鷹架時，因過失掉落 榔頭，致路人丁受傷。下列敘述何者正確？', '["甲無須為丙之行為，對丁負損害賠償責任", "乙無須為丙之行為，對丁負損害賠償責任", "甲與乙均無須為丙之行為負損害賠償責任", "甲與乙對丙之行為應連帶負損害賠償責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:25+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "320", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL)
